  Custom custom = context.getObjectByName(Custom.class, "ProvisioningTransaction Get Add Operation Entitlement");
  if (custom == null) {
    throw new GeneralException("The Custom Object with 'ProvisioningTransaction Get Add Operation Entitlement' is not exist");
  }
  String provTransactionId = custom.get("latestProvisioningTransactionID");
  if (provTransactionId == null || provTransactionId.isEmpty()) {
    throw new GeneralException("latestProvisoningTransactionID  key value is null or Empty");
  }
  String query = "sql:SELECT name FROM identityiq.spt_provisioning_transaction where name > " + provTransactionId + " and attributes LIKE '%op=\"Add\"%' and status='Success' and source='IdentityRefresh' and operation='Create' and application_name in('AD_Active-Directory','WBG - Azure AD','IDM_LDAP-Linux') order by name DESC";
  List finalList = new ArrayList();
  Iterator provTransacNames = context.search(query, null, null);
  while (provTransacNames.hasNext()) {

    String[]row = provTransacNames.next();
    ProvisioningTransaction transaction = context.getObjectByName(ProvisioningTransaction.class, row[0]);
    Identity identity = context.getObjectByName(Identity.class, row[1]);
    Application application = context.getObjectByName(Application.class, row[2]);

    List listOfGroupAttributes = application.getAccountSchema().getGroupAttributes();
    Attributes attributes = transaction.getAttributes();
    List listOfAttributeRequest = attributes.get("request").getAttributeRequests();

    for (AttributeRequest attributeRequest: listOfAttributeRequest) {
      if (listOfGroupAttributes.contains(attributeRequest.getName())) {
        List listOfEntitlements = new ArrayList();
        if (attributeRequest.getValue()instanceof List) {
          listOfEntitlements = attributeRequest.getValue();
        } else if (attributeRequest.getValue()instanceof String) {
          listOfEntitlements.add(attributeRequest.getValue());
        }
        for (String entitlement: Util.safeIterable(listOfEntitlements)) {
          Filter filter = Filter.subquery("id", BundleProfileRelation.class, "bundleId", Filter.and(Filter.eq("value", entitlement), Filter.notnull("sourceBundleId")));
          qo.add(filter);
          List listOfBR_entName = context.getObjects(Bundle.class, qo);
          List listOfBundleObjOnIden = new ArrayList();
          listOfBundleObjOnIden = identity.getAssignedRoles();
          List listOfBR_IdenNames = ObjectUtil.getObjectNames(listOfBundleObjOnIden);

          if (Util.nullSafeSize(listOfBR_entName) > 0 @and Util.nullSafeSize(listOfBR_IdenNames) > 0) {

            for (String brName: listOfBR_entName) {
              if(listOfBR_IdenNames.contains(brName)){
                found = true;
              }
            }
            if(!found){
              finalList.add(row[1]+":"+row[1]+":"+entitlement);
            }
          }
        }
      }
    }
  }

  return finalList;












































